#pragma OPENCL EXTENSION cl_khr_fp64 : enable

__kernel void hotspotOpt1(__global float *p, __global float* tIn, __global float *tOut, float sdc,
        int nx, int ny, int nz,
        float ce, float cw, 
        float cn, float cs,
        float ct, float cb, 
        float cc) 
{
    float amb_temp = 80.0f;

    int i = get_global_id(0);  
    int j = get_global_id(1);

    if (i >= nx || j >= ny) return;

    int c = i + j * nx;
    int xy = nx * ny;

    int W = (0 == i)        ? c : c - 1;
    int E = (nx-1 == i)     ? c : c + 1;
    int N = (0 == j)        ? c : c - nx;
    int S = (ny-1 == j)     ? c : c + nx;

    float temp1, temp2, temp3;
    temp1 = temp2 = tIn[c];
    temp3 = tIn[c+xy];
    tOut[c] = cc * temp2 + cw * tIn[W] + ce * tIn[E] + cs * tIn[S]
        + cn * tIn[N] + cb * temp1 + ct * temp3 + sdc * p[c] + ct * amb_temp;
    c = c + (xy);
    W = W + (xy);
    E = E + (xy);
    N = N + (xy);
    S = S + (xy);

    for (int k = 1; k < nz-1; ++k) {
        temp1 = temp2;
        temp2 = temp3;
        temp3 = tIn[c+xy];
        tOut[c] = cc * temp2 + cw * tIn[W] + ce * tIn[E] + cs * tIn[S]
            + cn * tIn[N] + cb * temp1 + ct * temp3 + sdc * p[c] + ct * amb_temp;
        c = c + (xy);
        W = W + (xy);
        E = E + (xy);
        N = N + (xy);
        S = S + (xy);
    }
    temp1 = temp2;
    temp2 = temp3;
    tOut[c] = cc * temp2 + cw * tIn[W] + ce * tIn[E] + cs * tIn[S]
        + cn * tIn[N] + cb * temp1 + ct * temp3 + sdc * p[c] + ct * amb_temp;
    return;
}
